using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 2);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 3, 4 }, 5, 2, 2);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 5, 1, 2);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 5 }, 5, 3, 2);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
            Assert.Equal(10, result[4]);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(5, result[4]);
            Assert.True(result.HasNextPage);
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
            Assert.False(result.HasNextPage);
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_RoundsUpCorrectly()
        {
            // 7 items, page size 3 = ceil(7/3) = 3 pages
            var list = new PaginatedList<int>(new List<int> { 1 }, 7, 1, 3);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            // 6 items, page size 3 = 2 pages
            var list = new PaginatedList<int>(new List<int> { 1 }, 6, 1, 3);
            Assert.Equal(2, list.TotalPages);
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after each test
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("Course", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("42", notification.Message);
            Assert.Contains("Student", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Instructor", "3", "John Doe", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultsUserToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_TwoParamOverload_Works()
        {
            _service.SendNotification("Student", "1", EntityOperation.UPDATE, "testUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }
    }
}

