using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student
                {
                    ID = 1,
                    LastName = "Alexander",
                    FirstMidName = "Carson",
                    EnrollmentDate = DateTime.Parse("2020-09-01")
                },
                new Student
                {
                    ID = 2,
                    LastName = "Alonso",
                    FirstMidName = "Meredith",
                    EnrollmentDate = DateTime.Parse("2021-09-01")
                },
                new Student
                {
                    ID = 3,
                    LastName = "Anand",
                    FirstMidName = "Arturo",
                    EnrollmentDate = DateTime.Parse("2021-09-01")
                },
                new Student
                {
                    ID = 4,
                    LastName = "Barzdukas",
                    FirstMidName = "Gytis",
                    EnrollmentDate = DateTime.Parse("2022-09-01")
                },
                new Student
                {
                    ID = 5,
                    LastName = "Li",
                    FirstMidName = "Yan",
                    EnrollmentDate = DateTime.Parse("2022-09-01")
                }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            context.Departments.AddRange(
                new Department
                {
                    DepartmentID = 1,
                    Name = "English",
                    Budget = 350000,
                    StartDate = DateTime.Parse("2007-09-01"),
                    RowVersion = new byte[] { 0, 0, 0, 0, 0, 0, 0, 1 }
                },
                new Department
                {
                    DepartmentID = 2,
                    Name = "Mathematics",
                    Budget = 100000,
                    StartDate = DateTime.Parse("2007-09-01"),
                    RowVersion = new byte[] { 0, 0, 0, 0, 0, 0, 0, 2 }
                },
                new Department
                {
                    DepartmentID = 3,
                    Name = "Engineering",
                    Budget = 350000,
                    StartDate = DateTime.Parse("2007-09-01"),
                    RowVersion = new byte[] { 0, 0, 0, 0, 0, 0, 0, 3 }
                }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            context.Courses.AddRange(
                new Course
                {
                    CourseID = 1050,
                    Title = "Chemistry",
                    Credits = 3,
                    DepartmentID = 3
                },
                new Course
                {
                    CourseID = 4022,
                    Title = "Microeconomics",
                    Credits = 3,
                    DepartmentID = 2
                },
                new Course
                {
                    CourseID = 4041,
                    Title = "Macroeconomics",
                    Credits = 3,
                    DepartmentID = 2
                }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    ID = 10,
                    LastName = "Abercrombie",
                    FirstMidName = "Kim",
                    HireDate = DateTime.Parse("1995-03-11"),
                    CourseAssignments = new List<CourseAssignment>()
                },
                new Instructor
                {
                    ID = 11,
                    LastName = "Fakhouri",
                    FirstMidName = "Fadi",
                    HireDate = DateTime.Parse("2002-07-06"),
                    CourseAssignments = new List<CourseAssignment>()
                },
                new Instructor
                {
                    ID = 12,
                    LastName = "Harui",
                    FirstMidName = "Roger",
                    HireDate = DateTime.Parse("1998-07-01"),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }

        public static void SeedAll(SchoolContext context)
        {
            SeedInstructors(context);
            SeedDepartments(context);

            context.Courses.AddRange(
                new Course
                {
                    CourseID = 1050,
                    Title = "Chemistry",
                    Credits = 3,
                    DepartmentID = 3,
                    Enrollments = new List<Enrollment>(),
                    CourseAssignments = new List<CourseAssignment>()
                },
                new Course
                {
                    CourseID = 4022,
                    Title = "Microeconomics",
                    Credits = 3,
                    DepartmentID = 2,
                    Enrollments = new List<Enrollment>(),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();

            SeedStudents(context);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 1, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 2, Grade = Grade.B }
            );
            context.SaveChanges();

            context.CourseAssignments.Add(
                new CourseAssignment { CourseID = 1050, InstructorID = 10 }
            );
            context.SaveChanges();
        }
    }
}

