using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Alexander",
                FirstMidName = "Carson"
            };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void FullName_WorksForInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi"
            };

            Assert.Equal("Fakhouri, Fadi", instructor.FullName);
        }

        [Fact]
        public void FullName_HandlesEmptyFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = ""
            };

            Assert.Equal("Smith, ", student.FullName);
        }
    }

    public class ErrorViewModelTests
    {
        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsTrue_WhenRequestIdHasValue()
        {
            var model = new ErrorViewModel { RequestId = "abc-123" };
            Assert.True(model.ShowRequestId);
        }
    }
}

