using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };

            // Drain any leftover notifications from the static queue
            while (true)
            {
                var result = _controller.GetNotifications() as JsonResult;
                var value = result.Value;
                var countProp = value.GetType().GetProperty("count");
                if (countProp != null && (int)countProp.GetValue(value) == 0)
                    break;
            }
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJsonWithSuccess()
        {
            var result = _controller.GetNotifications() as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_ReturnsEmptyWhenNoNotifications()
        {
            var result = _controller.GetNotifications() as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_ReturnsNotificationsFromQueue()
        {
            // Use the notification service from the base controller to send a notification
            _controller.notificationService.SendNotification("Test", "1", Models.EntityOperation.CREATE);

            var result = _controller.GetNotifications() as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.True((int)countProp.GetValue(value) > 0);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonWithSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }
    }
}

