            {
                var context = TestHelpers.CreateInMemoryContext();
                TestHelpers.SeedDepartments(context);
                var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
                controller.ControllerContext = new ControllerContext
                {
                    HttpContext = new DefaultHttpContext()
                };
                var course = new Course
                {
                    CourseID = 1000,
                    Title = "Test",
                    Credits = 3,
                    DepartmentID = 1
                };
