        }

        [Fact]
        public void DeleteConfirmed_DeletesAssociatedImage()
        {
            TestHelpers.SeedCourses(_context);

            // Create a file to simulate an existing image
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
