using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new StudentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Yan", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Li", model[0].LastName);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Li", model[0].LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsAscendingDateOrder()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsDescendingDateOrder()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // Most recent enrollment date first
            var firstDate = model[0].EnrollmentDate;
            var lastDate = model[model.Count - 1].EnrollmentDate;
            Assert.True(firstDate >= lastDate);
        }

        [Fact]
        public void Index_DefaultSort_ReturnsAscendingNameOrder()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
        }

        [Fact]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            // Seed more than 10 students
            for (int i = 1; i <= 15; i++)
            {
                _context.Students.Add(new Student
                {
                    ID = i,
                    LastName = $"Student{i:D2}",
                    FirstMidName = $"First{i}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            _context.SaveChanges();

            var page1 = _controller.Index(null, null, null, 1) as ViewResult;
            var model1 = Assert.IsType<PaginatedList<Student>>(page1.Model);
            Assert.Equal(10, model1.Count);

            var page2 = _controller.Index(null, null, null, 2) as ViewResult;
            var model2 = Assert.IsType<PaginatedList<Student>>(page2.Model);
            Assert.Equal(5, model2.Count);
        }

        [Fact]
        public void Index_NewSearch_ResetsPage()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            // When searchString is not null, page should reset to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            Assert.Equal("Date", result.ViewData["CurrentSort"]);
            Assert.Equal("test", result.ViewData["CurrentFilter"]);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, "Alexander", null, 1) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Students);
        }

        [Fact]
        public void Create_POST_SavesStudentToDb()
        {
            var student = new Student
            {
                LastName = "SaveTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-06-01")
            };

            _controller.Create(student);

            var saved = _context.Students.First();
            Assert.Equal("SaveTest", saved.LastName);
            Assert.Equal("Student", saved.FirstMidName);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Empty(_context.Students);
        }

        [Fact]
        public void Create_POST_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        [Fact]
        public void Create_POST_DateBelow1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ReturnsViewWithStudent()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedStudents(_context);

            var student = new Student
            {
                ID = 1,
                LastName = "UpdatedName",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            // Detach tracked entity
            var tracked = _context.Students.Local.FirstOrDefault(s => s.ID == 1);
            if (tracked != null)
                _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsViewWithStudent()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
            Assert.Null(_context.Students.Find(1));
        }

        #endregion
    }
}

