using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenNoDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_GET_ReturnsView()
        {
            // Seed instructors for the SelectList
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedInstructors(_context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2023-01-01"),
                InstructorID = 10
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_SavesDepartmentToDb()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2023-01-01")
            };

            _controller.Create(department);

            Assert.Single(_context.Departments);
            Assert.Equal("Physics", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            TestHelpers.SeedInstructors(_context);

            var department = new Department
            {
                Budget = 200000,
                StartDate = DateTime.Parse("2023-01-01")
            };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.Empty(_context.Departments);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Edit_POST_ValidModel_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);

            // Detach tracked entity
            var tracked = _context.Departments.Local.FirstOrDefault(d => d.DepartmentID == 1);
            if (tracked != null)
                _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var department = new Department
            {
                DepartmentID = 1,
                Name = "UpdatedEnglish",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 10,
                RowVersion = new byte[] { 0, 0, 0, 0, 0, 0, 0, 1 }
            };

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            TestHelpers.SeedInstructors(_context);

            var department = new Department
            {
                DepartmentID = 1,
                Budget = 200000,
                StartDate = DateTime.Parse("2023-01-01")
            };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Departments.Count());
            Assert.Null(_context.Departments.Find(1));
        }

        #endregion
    }
