using System;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        private Mock<IFormFile> CreateMockFile(string fileName, long length, byte[] content = null)
        {
            content ??= new byte[length];
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(stream => stream.Write(content, 0, content.Length));
            return mock;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenNoCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_GET_ReturnsViewWithNewCourse()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        [Fact]
        public void Create_POST_ValidModel_NoFile_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5050,
                Title = "Physics",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Courses);
        }

        [Fact]
        public void Create_POST_ValidModel_WithImage_SavesFileAndRedirects()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5050,
                Title = "Physics",
                Credits = 4,
                DepartmentID = 1
            };
            var mockFile = CreateMockFile("test.jpg", 1024, new byte[1024]);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = _context.Courses.Find(5050);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_InvalidExtension_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5050,
                Title = "Physics",
                Credits = 4,
                DepartmentID = 1
            };
            var mockFile = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
            Assert.Empty(_context.Courses);
        }

        [Fact]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5050,
                Title = "Physics",
                Credits = 4,
                DepartmentID = 1
            };
            var mockFile = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            TestHelpers.SeedDepartments(_context);

            var course = new Course { CourseID = 5050, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.Empty(_context.Courses);
        }

        [Fact]
        public void Create_POST_AllowedImageExtensions_AreAccepted()
        {
            var extensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };
            foreach (var ext in extensions)
            {
                var context = TestHelpers.CreateInMemoryContext();
                TestHelpers.SeedDepartments(context);
                var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
                controller.ControllerContext = new ControllerContext
                {
                    HttpContext = new DefaultHttpContext()
                };
                var course = new Course
                {
                    CourseID = 1000,
                    Title = "Test",
                    Credits = 3,
                    DepartmentID = 1
                };
                var mockFile = CreateMockFile($"test{ext}", 100, new byte[100]);

                var result = controller.Create(course, mockFile.Object) as RedirectToActionResult;

                Assert.NotNull(result);
                controller.Dispose();
                context.Dispose();
            }
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenCourseNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ReturnsViewWithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
