using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new HomeController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithEnrollmentDateGroups()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            // Our seed data has 3 distinct dates (2020, 2021, 2022)
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void About_ReturnsCorrectStudentCounts()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.Equal(5, totalStudents);
        }

        [Fact]
        public void About_ReturnsEmptyList_WhenNoStudents()
        {
            var result = _controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", result.ViewData["Message"]);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["Message"]);
            Assert.Contains("permission", result.ViewData["Message"].ToString());
        }
    }
}

